}

.container {
  width: 100%;
  max-width: 1100px;
  margin: 0 auto;
  min-width: 0;
}

.dns-records-toolbar-group-search {
  grid-template-rows: minmax(14px, auto) 32px auto;
  align-self: start;
}

h1 {
  font-size: 22px;
  margin: 0 0 18px 0;
}

.top-bar {
