    },
    'hi-IN': {
      s7t: '7. ब्राउज़र संग्रहण और कुकी सहमति',
      s7b: 'यह टूल सहमति की स्थिति के लिए आपके ब्राउज़र के <code>localStorage</code> का उपयोग करता है और, यदि आप अनुमति दें, तो थीम, भाषा और हाल का डोमेन इतिहास भी वहीं रखता है। यदि आप गुमनाम विश्लेषण की अनुमति देते हैं, तो यह टूल केवल कुल गणना के लिए एक अस्थायी प्रथम-पक्ष सत्र कुकी भी जारी कर सकता है।',
      s7l1: 'आवश्यक संग्रहण आपकी सहमति पसंद को सुरक्षित रखता है ताकि टूल उसका सम्मान कर सके।',
      s7l2: 'प्राथमिकता संग्रहण वैकल्पिक है और केवल थीम, भाषा और हाल की खोज इतिहास को आपके ब्राउज़र में रखता है।',
      s7l3: 'विश्लेषण संग्रहण वैकल्पिक है और सक्षम होने पर इसमें एक अस्थायी प्रथम-पक्ष सत्र कुकी और गुमनाम कुल काउंटर शामिल हो सकते हैं।',
      manageCookies: 'कुकी सेटिंग्स प्रबंधित करें'
    },
    'ja-JP': {
      s7t: '7. ブラウザー保存領域とCookie同意',
      s7b: '本ツールは同意状態の保存にブラウザーの <code>localStorage</code> を使用し、許可された場合はテーマ、言語、最近のドメイン履歴も保存します。匿名分析を許可した場合は、集計カウント専用の一時的なファーストパーティ セッション Cookie を発行することがあります。',
      s7l1: '必須保存領域は、ツールが同意内容を尊重できるように、あなたの選択を保持します。',
      s7l2: '設定保存は任意であり、テーマ、言語、最近の検索履歴のみをブラウザーに保持します。',
      s7l3: '分析保存は任意であり、有効な場合は一時的なファーストパーティ セッション Cookie と匿名の集計カウンターを含むことがあります。',
      manageCookies: 'Cookie設定を管理'
    },
    'ru-RU': {
      s7t: '7. Хранилище браузера и согласие на cookie',
      s7b: 'Инструмент использует <code>localStorage</code> браузера для хранения состояния согласия и, если вы это разрешите, для сохранения темы, языка и недавней истории доменов. Если вы разрешаете анонимную аналитику, инструмент также может установить временный собственный cookie сессии только для агрегированных подсчетов.',
      s7l1: 'Обязательное хранилище сохраняет ваш выбор согласия, чтобы инструмент мог его соблюдать.',
      s7l2: 'Хранилище предпочтений является необязательным и сохраняет только тему, язык и недавнюю историю запросов в вашем браузере.',
      s7l3: 'Хранилище аналитики является необязательным и при включении может включать временный собственный cookie сессии и анонимные агрегированные счетчики.',
      manageCookies: 'Управление настройками cookie'
    }
  };

  Object.keys(PRIVACY_CONSENT_OVERRIDES).forEach(code => {
    TRANSLATIONS[code] = Object.assign({}, TRANSLATIONS[code] || TRANSLATIONS.en, PRIVACY_CONSENT_OVERRIDES[code]);
  });

  function normalizeLanguageCode(lang) {
    const value = String(lang || '').trim().toLowerCase();
    if (!value) return 'en';
    if (value === 'ptbr' || value.startsWith('pt-br') || value.startsWith('pt_br') || value.startsWith('pt')) return 'pt-BR';
    if (value.startsWith('es')) return 'es';
    if (value.startsWith('fr')) return 'fr';
    if (value.startsWith('de')) return 'de';
    if (value.startsWith('ar')) return 'ar';
    if (value === 'zh' || value.startsWith('zh-cn') || value.startsWith('zh_cn') || value.startsWith('zh-hans')) return 'zh-CN';
    if (value === 'hi' || value.startsWith('hi-in') || value.startsWith('hi_in')) return 'hi-IN';
    if (value === 'ja' || value.startsWith('ja-jp') || value.startsWith('ja_jp')) return 'ja-JP';
    if (value === 'ru' || value.startsWith('ru-ru') || value.startsWith('ru_ru')) return 'ru-RU';
    return 'en';
  }

  const params = new URLSearchParams(window.location.search);
  const lang = normalizeLanguageCode(params.get('lang') || navigator.language || 'en');
  const t = TRANSLATIONS[lang] || TRANSLATIONS.en;
  document.documentElement.lang = lang;
  document.documentElement.dir = lang === 'ar' ? 'rtl' : 'ltr';
  document.title = t.pageTitle;

  const setText = (id, value) => { const el = document.getElementById(id); if (el) el.textContent = value; };
  const setHtml = (id, value) => { const el = document.getElementById(id); if (el) el.innerHTML = value; };

  setText('privacyBackLink', t.back);
  document.getElementById('privacyBackLink').href = '/?lang=' + encodeURIComponent(lang);
  setText('privacyTitle', t.title);
  setText('privacyUpdatedLabel', t.updatedLabel);
  setText('privacyUpdatedValue', t.updatedValue);
  setText('privacySection1Title', t.s1t); setText('privacySection1Body', t.s1b);
  setText('privacySection2Title', t.s2t); setHtml('privacySection2Item1', t.s2l1); setHtml('privacySection2Item2', t.s2l2); setHtml('privacySection2Item3', t.s2l3);
  setText('privacySection3Title', t.s3t); setText('privacySection3Intro', t.s3i); setText('privacySection3Item1', t.s3l1); setText('privacySection3Item2', t.s3l2); setText('privacySection3Item3', t.s3l3); setHtml('privacySection3Body', t.s3b);
  setText('privacySection4Title', t.s4t); setText('privacySection4Body', t.s4b);
  setText('privacySection5Title', t.s5t); setText('privacySection5Body', t.s5b);
  setText('privacySection6Title', t.s6t); setText('privacySection6Body', t.s6b);
  setText('privacySection7Title', t.s7t); setHtml('privacySection7Body', t.s7b);
  setText('privacySection7Item1', t.s7l1);
  setText('privacySection7Item2', t.s7l2);
  setText('privacySection7Item3', t.s7l3);
  setText('privacySection8Title', t.s8t); setText('privacySection8Body', t.s8b);
  setText('privacySection9Title', t.s9t); setText('privacySection9Body', t.s9b);
  setText('privacySection10Title', t.s10t); setHtml('privacySection10Body', t.s10b);
  const privacyManageCookiesLink = document.getElementById('privacyManageCookiesLink');
  if (privacyManageCookiesLink) {
    privacyManageCookiesLink.textContent = t.manageCookies || 'Manage cookie settings';
    privacyManageCookiesLink.href = '/?lang=' + encodeURIComponent(lang) + '&openCookieSettings=1';
  }
})();
</script>
</body>
</html>
'@

# Optional local MSAL script path (for environments that block CDNs)
$msalLocalPath = $env:ACS_MSAL_LOCAL_PATH
if ([string]::IsNullOrWhiteSpace($msalLocalPath)) {
  $msalLocalPath = Join-Path -Path $PSScriptRoot -ChildPath 'msal-browser.min.js'
}
$msalLocalPath = [System.IO.Path]::GetFullPath($msalLocalPath)

if (-not (Test-Path -LiteralPath $msalLocalPath)) {
  $msalNodePath = Join-Path -Path $PSScriptRoot -ChildPath 'node_modules\@azure\msal-browser\lib\msal-browser.min.js'
  if (Test-Path -LiteralPath $msalNodePath) {
    $msalLocalPath = [System.IO.Path]::GetFullPath($msalNodePath)
  }
}

if (-not (Test-Path -LiteralPath $msalLocalPath) -and $env:ACS_MSAL_AUTO_INSTALL -eq '1') {
  $npmCmd = $null
  try { $npmCmd = Get-Command -Name npm -ErrorAction SilentlyContinue } catch { $npmCmd = $null }
  if ($npmCmd) {
    try {
      Write-Information -InformationAction Continue -MessageData "MSAL bundle missing. Running npm install @azure/msal-browser@latest in $PSScriptRoot..."
      & $npmCmd.Source install --no-fund --no-audit --prefix $PSScriptRoot @azure/msal-browser@latest | Out-Null
      if ($LASTEXITCODE -ne 0) {
        Write-Information -InformationAction Continue -MessageData "MSAL auto-install exited with code $LASTEXITCODE."
      }
    } catch {
      Write-Information -InformationAction Continue -MessageData "MSAL auto-install failed: $($_.Exception.Message)"
    }
  } else {
    Write-Information -InformationAction Continue -MessageData 'MSAL auto-install skipped: npm not found in PATH.'
  }

  $npmRoot = $null
  try {
    $npmRoot = (& $npmCmd.Source root --prefix $PSScriptRoot 2>$null | Select-Object -First 1)
  } catch { $npmRoot = $null }
  if (-not [string]::IsNullOrWhiteSpace($npmRoot)) {
    Write-Information -InformationAction Continue -MessageData "npm root (local): $npmRoot"
  }
  if (-not [string]::IsNullOrWhiteSpace($npmRoot)) {
    $msalNodePath = Join-Path -Path $npmRoot -ChildPath '@azure\msal-browser\lib\msal-browser.min.js'
  } else {
    $msalNodePath = Join-Path -Path $PSScriptRoot -ChildPath 'node_modules\@azure\msal-browser\lib\msal-browser.min.js'
  }

  $npmGlobalRoot = $null
  try {
    $npmGlobalRoot = (& $npmCmd.Source root -g 2>$null | Select-Object -First 1)
  } catch { $npmGlobalRoot = $null }
  if (-not [string]::IsNullOrWhiteSpace($npmGlobalRoot)) {
    Write-Information -InformationAction Continue -MessageData "npm root (global): $npmGlobalRoot"
  }

  if (Test-Path -LiteralPath $msalNodePath) {
    $msalLocalPath = [System.IO.Path]::GetFullPath($msalNodePath)
  } else {
    $globalCandidate = if ($npmGlobalRoot) { Join-Path -Path $npmGlobalRoot -ChildPath '@azure\msal-browser\lib\msal-browser.min.js' } else { $null }
    if ($globalCandidate -and (Test-Path -LiteralPath $globalCandidate)) {
      $msalLocalPath = [System.IO.Path]::GetFullPath($globalCandidate)
    } else {
      Write-Information -InformationAction Continue -MessageData "MSAL bundle not found after npm install. Expected at: $msalNodePath"
    }
  }
}

# Local static asset root used for same-origin UI assets such as Lucide SVG icons
# and language flag SVGs. These are optional but avoid third-party CDN fetches
# that can trigger browser tracking-prevention warnings.
$script:AssetsRoot = Join-Path -Path $PSScriptRoot -ChildPath 'assets'

if (Test-Path -LiteralPath $msalLocalPath) {
  Write-Information -InformationAction Continue -MessageData "MSAL local script detected at: $msalLocalPath"
} else {
  Write-Information -InformationAction Continue -MessageData "MSAL local script not found at: $msalLocalPath"
}

if ([string]::IsNullOrWhiteSpace($entraClientId)) {
  Write-Information -InformationAction Continue -MessageData 'ACS_ENTRA_CLIENT_ID not detected. Microsoft sign-in will be disabled.'
} else {
  Write-Information -InformationAction Continue -MessageData "ACS_ENTRA_CLIENT_ID detected"
}

if ([string]::IsNullOrWhiteSpace($entraTenantId)) {
  Write-Information -InformationAction Continue -MessageData 'ACS_ENTRA_TENANT_ID not set. Using organizations authority.'
} else {
  Write-Information -InformationAction Continue -MessageData "ACS_ENTRA_TENANT_ID detected"
}

# ===== Runspace Pool Initialization =====
# ------------------- MAIN LOOP -------------------
# Request handling uses a RunspacePool to process multiple HTTP requests concurrently.
# This keeps the UI responsive while DNS lookups are in flight.
# Each incoming request is dispatched to a PowerShell runspace from the pool, which
# executes the $handlerScript (defined below). The main thread only accepts connections
# and dispatches; all DNS work happens in runspace workers.

# Maximum number of concurrent request-handling runspaces.
$maxConcurrentRequests = 64

# Per-domain/route throttling: only one lookup for the same domain + endpoint at a time.
# This prevents duplicate requests from hammering DNS while still allowing independent
# lookup stages (TXT, MX, WHOIS, DMARC, etc.) to run in parallel for the same domain.

$domainLocks = [System.Collections.Concurrent.ConcurrentDictionary[string, System.Threading.SemaphoreSlim]]::new([System.StringComparer]::OrdinalIgnoreCase)

# List all functions that need to be available inside the runspace workers.
# These are injected into the InitialSessionState so each runspace can call them.
$functionNames = @(
  'Set-SecurityHeaders','Get-SecurityHeaderMap','Set-NoCacheHeaders','Write-Json','Write-Html','Write-FileResponse','Invoke-OutboundHttp',
  'New-AnonSessionId','Get-RequestCookies','Get-RequestHeaderValue','Get-AnonymousAnalyticsConsentState','Clear-AnonymousSessionCookie','Get-OrCreate-AnonymousSessionId',
  'Get-HashedDomain',
  'Get-AnonymousMetricsPersistPath','Load-AnonymousMetricsPersisted','Save-AnonymousMetricsPersisted','Set-AnonymousMetricsFilePermissions',
  'Update-AnonymousMetrics','Get-AnonymousMetricsSnapshot','Update-AnonymousAuthMetrics',
  'Get-RegistrableDomain','Get-ParentDomains','Test-WhoisRawTextHasUsableData','Test-WhoisResponseIsRegistryBlock','Get-WhoisCreationDateLabelRegex','Get-WhoisExpiryDateLabelRegex','Get-WhoisParsedRegistrationData','Get-FirstNonEmptyPropertyValue',
  'Resolve-DohName','ResolveSafely','Get-DnsIpString','Get-MxRecordObjects','Get-DnsRecordTypeCode','Get-DnsRecordTypeName','New-DnsRecordDetail','Format-DnsRecordDetailTtl','Convert-DnssecTimestampToDisplay','Get-DnsEscapedByteDisplay','Convert-DnsEscapedLabelToDisplay','Convert-DnsNameToDisplay','Convert-DnsBinaryDataToDisplay','Get-DnssecAlgorithmDisplay','Get-DnsRecordTypeDisplay','Get-DnsRecordDetails','Get-ReverseLookupSupplementTargets','Get-DnsRecordDataString','ConvertTo-ReverseLookupName','Resolve-DohRecordsDetailed','Resolve-DnsRecordsDetailed','Get-DnsRecordsStatus','ConvertTo-NormalizedDomain','Test-DomainName','Write-RequestLog','Get-DohDnssecAnomaly',
  'Get-SpfTokens','Test-SpfMacroText','Get-SpfDomainSpecTarget','Get-SpfMechanismType','Test-SpfOutlookIncludeToken','Find-SpfOutlookRequirementMatch','Get-SpfOutlookRequirementStatus','Get-SpfNestedAnalysis','Format-SpfNestedAnalysisText','Get-SpfGuidance',
  'Get-ClientIp','Test-IsTrustedProxy','Get-ApiKeyFromRequest','Test-StringEqualsConstantTime','Test-ApiKey','Test-RateLimit',
  'Get-DnsBaseStatus','Get-DnsMxStatus','Get-DnsDmarcStatus','Get-DnsDkimStatus','Get-CnameTargetFromRecords','Get-DnsCnameStatus','Invoke-RblLookup','ConvertTo-ReversedIpv4','Get-DnsReputationStatus',
  'Get-RblCacheEntry','Set-RblCacheEntry','Clear-ExpiredRblCacheEntries',
  'Get-RdapBootstrapData','Get-RdapBuiltInTldMap','Get-RdapBaseUrlForDomain','Invoke-RdapLookup','Invoke-WhoisXmlLookup','Invoke-GoDaddyWhoisLookup','ConvertTo-NullableUtcIso8601','Get-DomainAgeDays','Get-DomainRegistrationStatus',
  'Get-DmarcSecurityGuidance',
  'Invoke-SysinternalsWhoisLookup','Invoke-LinuxWhoisLookup','Invoke-TcpWhoisLookup','Get-DomainAgeParts','Format-DomainAge','Get-TimeUntilParts','Format-ExpiryRemaining',
  'Get-AcsDnsStatus'
)

# Create an InitialSessionState that will be shared by all runspace workers.
# This seeds each runspace with the function definitions, shared variables, and config.
$iss = [System.Management.Automation.Runspaces.InitialSessionState]::CreateDefault()

# Provide a stable flag inside handler runspaces.
$iss.Variables.Add([System.Management.Automation.Runspaces.SessionStateVariableEntry]::new('AcsAnonMetricsEnabled', $anonMetricsEnabled, 'Anonymous metrics enabled flag'))
$iss.Variables.Add([System.Management.Automation.Runspaces.SessionStateVariableEntry]::new('MetricsHashKey', $MetricsHashKey, 'Hash key used for anonymous domain hashing'))
$iss.Variables.Add([System.Management.Automation.Runspaces.SessionStateVariableEntry]::new('GoDaddyApiKey', $script:GoDaddyApiKey, 'GoDaddy API key'))
$iss.Variables.Add([System.Management.Automation.Runspaces.SessionStateVariableEntry]::new('GoDaddyApiSecret', $script:GoDaddyApiSecret, 'GoDaddy API secret'))

# Share the global metrics objects with handler runspaces (must be added before pool creation).
$iss.Variables.Add([System.Management.Automation.Runspaces.SessionStateVariableEntry]::new('AcsMetrics', $global:AcsMetrics, 'Shared metrics object'))
$iss.Variables.Add([System.Management.Automation.Runspaces.SessionStateVariableEntry]::new('AcsMetricsPersistLock', $global:AcsMetricsPersistLock, 'Shared metrics persist lock'))
$iss.Variables.Add([System.Management.Automation.Runspaces.SessionStateVariableEntry]::new('AcsUptime', $global:AcsUptime, 'Shared uptime stopwatch'))
$iss.Variables.Add([System.Management.Automation.Runspaces.SessionStateVariableEntry]::new('AcsRateLimitStore', $global:AcsRateLimitStore, 'Shared rate limit store'))
$iss.Variables.Add([System.Management.Automation.Runspaces.SessionStateVariableEntry]::new('AcsRateLimitLock', $global:AcsRateLimitLock, 'Shared rate limit lock'))

foreach ($name in $functionNames) {
  # Copy function *definitions* into the runspace pool so handler runspaces can call them.
  $cmd = Get-Command -Name $name -CommandType Function -ErrorAction SilentlyContinue
  if (-not $cmd -and $name -eq 'Invoke-LinuxWhoisLookup') {
    # Define a no-op placeholder for Windows hosts where Invoke-LinuxWhoisLookup isn't defined/needed.
    function Invoke-LinuxWhoisLookup { param([string]$Domain,[string]$WhoisPath,[int]$TimeoutSec = 25,[switch]$ThrowOnError) return $null }
    $cmd = Get-Command -Name $name -CommandType Function -ErrorAction SilentlyContinue
  }
  if (-not $cmd) { continue }
  $def = $cmd.Definition
  $iss.Commands.Add([System.Management.Automation.Runspaces.SessionStateFunctionEntry]::new($name, $def))
}

# Create and open the RunspacePool. Workers will be allocated from this pool on demand.
$pool = [System.Management.Automation.Runspaces.RunspaceFactory]::CreateRunspacePool(1, $maxConcurrentRequests, $iss, $Host)
$pool.Open()

# Track in-flight async invocations so we can dispose them promptly from the main runspace.
$inflight = [System.Collections.Concurrent.ConcurrentDictionary[string, object]]::new([System.StringComparer]::OrdinalIgnoreCase)

function Complete-InflightInvocation {
  param(
    [Parameter(Mandatory = $true)]
    [string]$InvocationId,

    [switch]$Force
  )

  $item = $null
  if (-not $inflight.TryGetValue($InvocationId, [ref]$item)) { return }
  if (-not $Force -and -not $item.Async.IsCompleted) { return }

  if ($inflight.TryRemove($InvocationId, [ref]$item)) {
    $completed = $false
    try { $completed = ($item.Async -and $item.Async.IsCompleted) } catch { $completed = $false }

    if ($completed) {
      try { $item.Ps.EndInvoke($item.Async) } catch { $null = $_ }
    }
    elseif ($Force) {
      try { $item.Ps.Stop() } catch { $null = $_ }
    }

    try {
      if ($item.Async -and $item.Async.AsyncWaitHandle) {
        $item.Async.AsyncWaitHandle.Close()
      }
    } catch { $null = $_ }
    try { $item.Ps.Dispose() } catch { $null = $_ }
  }
}

function Register-InflightInvocation {
  param(
    [Parameter(Mandatory = $true)]
    [System.Management.Automation.PowerShell]$PowerShellInstance,

    [Parameter(Mandatory = $true)]
    [object]$AsyncResult
  )

  $invocationId = [Guid]::NewGuid().ToString('N')
  $item = [pscustomobject]@{
    Ps = $PowerShellInstance
    Async = $AsyncResult
  }

  $null = $inflight.TryAdd($invocationId, $item)

  return $invocationId
}

# Reap any completed async PowerShell invocations from the main runspace.
function Invoke-InflightCleanup {
  foreach ($invocationId in @($inflight.Keys)) {
    Complete-InflightInvocation -InvocationId $invocationId
  }
}

# ===== Per-Request Handler Script =====
# ------------------- PER-REQUEST HANDLER SCRIPT -------------------
# This here-string is the script block that runs inside each RunspacePool worker
# for every incoming HTTP request. It receives the request context, routes by URL path,
# and dispatches to the appropriate DNS check function or serves the HTML UI.
$handlerScript = @'
param($ctx, $htmlPage, $domainLocks, $msalLocalPath, $tosPageHtml, $privacyPageHtml, $assetsRoot)

# TcpListener shim may not always provide a fully populated Url object.
$path = $null
try { if ($ctx -and $ctx.Request -and $ctx.Request.Url) { $path = $ctx.Request.Url.AbsolutePath } } catch { $path = $null }
if ([string]::IsNullOrWhiteSpace($path)) {
  try {
    $raw = $null
    try { if ($ctx -and $ctx.Request -and $ctx.Request.Url) { $raw = [string]$ctx.Request.Url } } catch { $raw = $null }
    if ([string]::IsNullOrWhiteSpace($raw)) {
      # Some shims expose only a raw target string
      try { if ($ctx -and $ctx.Request -and $ctx.Request.RawUrl) { $raw = [string]$ctx.Request.RawUrl } } catch { $raw = $null }
    }
    if (-not [string]::IsNullOrWhiteSpace($raw)) {
      if ($raw.StartsWith('/')) {
        # Raw targets like "/api/metrics?x=y" are not absolute URIs
        $qIdx = $raw.IndexOf('?')
        $path = if ($qIdx -ge 0) { $raw.Substring(0, $qIdx) } else { $raw }
      } else {
        $u = [uri]$raw
        $path = $u.AbsolutePath
      }
    }
  } catch { $path = $null }
}
if ([string]::IsNullOrWhiteSpace($path)) { $path = '/' }

# SECURITY: Cap POST/PUT/PATCH request bodies before any handler runs. The
# only POST today is /api/consent which is header-driven and ignores the
# body, so any oversized body is wasted bandwidth and a tying-up vector for
# worker runspaces. The cap is configurable via ACS_MAX_REQUEST_BODY_BYTES
# (default 64 KB, set in 00-Header.ps1). Returning 413 early avoids reading
# the body at all.
try {
  $reqMethod = $null
  try { $reqMethod = [string]$ctx.Request.HttpMethod } catch { $reqMethod = $null }
  if ([string]::IsNullOrWhiteSpace($reqMethod)) {
    try { $reqMethod = [string]$ctx.Request.Method } catch { $reqMethod = $null }
  }
  if (-not [string]::IsNullOrWhiteSpace($reqMethod)) {
    $reqMethodUpper = $reqMethod.ToUpperInvariant()
    if ($reqMethodUpper -eq 'POST' -or $reqMethodUpper -eq 'PUT' -or $reqMethodUpper -eq 'PATCH') {
      $bodyCap = 65536
      if ($env:ACS_MAX_REQUEST_BODY_BYTES -and $env:ACS_MAX_REQUEST_BODY_BYTES -match '^\d+$') {
        $bodyCap = [int]$env:ACS_MAX_REQUEST_BODY_BYTES
      }
      $contentLength = -1
      try {
        if ($ctx.Request -is [System.Net.HttpListenerRequest]) {
          $contentLength = [int64]$ctx.Request.ContentLength64
        } else {
          $clHeader = $null
          try {
            if ($ctx.Request.Headers -and $ctx.Request.Headers.ContainsKey('content-length')) {
              $clHeader = [string]$ctx.Request.Headers['content-length']
            }
          } catch { $clHeader = $null }
          if (-not [string]::IsNullOrWhiteSpace($clHeader)) {
            $parsed = 0
            if ([int64]::TryParse($clHeader, [ref]$parsed)) { $contentLength = $parsed }
          }
        }
      } catch { $contentLength = -1 }
      if ($contentLength -gt $bodyCap) {
        Write-Json -Context $ctx -Object @{ error = 'Request body too large.'; maxBytes = $bodyCap } -StatusCode 413
        return
      }
    }
  }
} catch { }

# This script block runs inside the RunspacePool for each incoming request.
# Inputs:
# - $ctx         : the request/response context (HttpListenerContext or TcpListener shim)
# - $htmlPage    : the embedded SPA HTML (string)
# - $domainLocks : shared dictionary of per-domain semaphores

function Get-DomainSemaphore([string]$domain, [string]$scope) {
  # Get/create a per-domain+scope semaphore so duplicate work serializes, while
  # different lookup stages for the same domain can still run concurrently.
  $scopeKey = if ([string]::IsNullOrWhiteSpace($scope)) { 'default' } else { $scope.Trim() }
  $lockKey = if ([string]::IsNullOrWhiteSpace($domain)) { $scopeKey } else { "$scopeKey|$domain" }

  # SECURITY/MEMORY: prune idle semaphores when the dictionary grows large so a
  # long-running container that processes many distinct domains cannot leak
  # memory indefinitely. We only remove entries whose semaphore is currently
  # idle (CurrentCount == 1, meaning no holder, no waiters), so an in-flight
  # lookup is never disturbed. The threshold was lowered from 10k to 1k so a
  # request burst against many distinct domains cannot balloon the dictionary
  # before the next prune fires; the prune walk itself is bounded so a very
  # large dictionary cannot pin the request thread either.
  try {
    if ($domainLocks.Count -gt 1000) {
      $pruneBudget = 2000
      foreach ($existingKey in @($domainLocks.Keys)) {
        if ($pruneBudget -le 0) { break }
        $pruneBudget--
        $existingSem = $null
        if ($domainLocks.TryGetValue($existingKey, [ref]$existingSem)) {
          if ($existingSem -and $existingSem.CurrentCount -eq 1) {
            $removed = $null
            if ($domainLocks.TryRemove($existingKey, [ref]$removed)) {
              try { $removed.Dispose() } catch { }
            }
          }
        }
      }
    }
  } catch { }

  $sem = $null
  if (-not $domainLocks.TryGetValue($lockKey, [ref]$sem)) {
    $newSem = [System.Threading.SemaphoreSlim]::new(1, 1)
    if ($domainLocks.TryAdd($lockKey, $newSem)) {
      $sem = $newSem
    } else {
      $null = $domainLocks.TryGetValue($lockKey, [ref]$sem)
    }
  }
  return $sem
}

try {
# Anonymous metrics are only allowed after the browser explicitly sends
# analytics consent in the consent header. This prevents non-essential
# analytics cookies from being issued before the user opts in.
$metricsEnabled = ($env:ACS_ENABLE_ANON_METRICS -eq '1') -or ($true -eq $AcsAnonMetricsEnabled)
$analyticsConsentState = $null
if ($metricsEnabled) {
  $analyticsConsentState = Get-AnonymousAnalyticsConsentState -Context $ctx
  if ($false -eq $analyticsConsentState) {
    Clear-AnonymousSessionCookie -Context $ctx
  }
}

  # 1) Serve the UI
  if ($path -eq "/" -or $path -eq "/index.html") {
    $nonceBytes = [byte[]]::new(16)
    $rng = [System.Security.Cryptography.RandomNumberGenerator]::Create()
    try {
      $rng.GetBytes($nonceBytes)
    } finally {
      try { $rng.Dispose() } catch { }
    }
    $nonce = [Convert]::ToBase64String($nonceBytes)
    Write-Html -Context $ctx -Html $htmlPage -Nonce $nonce
    return
  }

  # 1-tos) Serve Terms of Service page
  if ($path -eq "/terms" -and -not [string]::IsNullOrWhiteSpace($tosPageHtml)) {
    $tosNonceBytes = [byte[]]::new(16); [System.Security.Cryptography.RandomNumberGenerator]::Create().GetBytes($tosNonceBytes)
    $tosNonce = [Convert]::ToBase64String($tosNonceBytes)
    Write-Html -Context $ctx -Html $tosPageHtml -Nonce $tosNonce
    return
  }

  # 1-privacy) Serve Privacy Statement page
  if ($path -eq "/privacy" -and -not [string]::IsNullOrWhiteSpace($privacyPageHtml)) {
    $privNonceBytes = [byte[]]::new(16); [System.Security.Cryptography.RandomNumberGenerator]::Create().GetBytes($privNonceBytes)
    $privNonce = [Convert]::ToBase64String($privNonceBytes)
    Write-Html -Context $ctx -Html $privacyPageHtml -Nonce $privNonce
    return
  }

  # 1a) Serve local MSAL bundle (optional)
  if ($path -eq "/assets/msal-browser.min.js") {
    Write-FileResponse -Context $ctx -Path $msalLocalPath -ContentType 'application/javascript'
    return
  }

  # 1a-assets) Serve local static assets from the repository assets folder.
  # Restrict responses to files beneath the configured assets root to prevent
  # path traversal from exposing arbitrary content on disk.
  if ($path.StartsWith('/assets/', [System.StringComparison]::OrdinalIgnoreCase) -and -not [string]::IsNullOrWhiteSpace($assetsRoot)) {
    try {
      $relativeAssetPath = $path.Substring(8) -replace '/', [System.IO.Path]::DirectorySeparatorChar
      $rootFullPath = [System.IO.Path]::GetFullPath($assetsRoot)
      $assetFullPath = [System.IO.Path]::GetFullPath((Join-Path -Path $rootFullPath -ChildPath $relativeAssetPath))

      # SECURITY: Append a directory separator before the prefix check so a
      # sibling directory whose name starts with the same prefix (for example
      # `C:\repo\assetsX\` vs `C:\repo\assets\`) cannot satisfy `StartsWith`.
      # On Windows the comparison stays case-insensitive; on case-sensitive
      # file systems we use ordinal comparison so an "/Assets/..." request
      # path will not slip through pointing at a different directory.
      $sep = [string][System.IO.Path]::DirectorySeparatorChar
      $rootFullPathWithSep = if ($rootFullPath.EndsWith($sep)) { $rootFullPath } else { $rootFullPath + $sep }
      # `$IsWindows` is only defined in PowerShell 7+. On Windows PowerShell
      # 5.1 (Desktop edition) the variable is unset, so we treat the
      # Desktop edition as Windows by definition.
      $isWindowsRuntime = $false
      try { if (Get-Variable -Name IsWindows -Scope Global -ErrorAction SilentlyContinue) { $isWindowsRuntime = [bool]$IsWindows } } catch { }
      if (-not $isWindowsRuntime -and $PSVersionTable.PSEdition -eq 'Desktop') { $isWindowsRuntime = $true }
      $comparisonMode = if ($isWindowsRuntime) {
        [System.StringComparison]::OrdinalIgnoreCase
      } else {
        [System.StringComparison]::Ordinal
      }
      if (-not $assetFullPath.StartsWith($rootFullPathWithSep, $comparisonMode) -and ($assetFullPath -ne $rootFullPath)) {
        Write-Json -Context $ctx -Object @{ error = 'Invalid asset path.' } -StatusCode 400
        return
      }

      $contentType = 'application/octet-stream'
      switch ([System.IO.Path]::GetExtension($assetFullPath).ToLowerInvariant()) {
        '.svg' { $contentType = 'image/svg+xml; charset=utf-8' }
        '.png' { $contentType = 'image/png' }
        '.jpg' { $contentType = 'image/jpeg' }
        '.jpeg' { $contentType = 'image/jpeg' }
        '.gif' { $contentType = 'image/gif' }
        '.webp' { $contentType = 'image/webp' }
        '.ico' { $contentType = 'image/x-icon' }
        '.js' { $contentType = 'application/javascript; charset=utf-8' }
        '.css' { $contentType = 'text/css; charset=utf-8' }
      }

      Write-FileResponse -Context $ctx -Path $assetFullPath -ContentType $contentType
      return
    } catch {
      Write-Json -Context $ctx -Object @{ error = 'Failed to load requested asset.' } -StatusCode 500
      return
    }
  }

  # 1b) Metrics endpoint handled by caller (fast-path in main loop). Keep here as safety net only.
  if ($path -eq "/api/metrics") {
    Handle-MetricsRequest -Context $ctx -MetricsEnabled $metricsEnabled
    return
  }

  # 1c) Consent sync endpoint. This is called by the SPA after the user saves
  # cookie preferences so the server can immediately clear any existing
  # analytics session cookie when analytics consent is rejected.
  # Rate-limited so a noisy client cannot pin a worker runspace by spamming
  # consent toggles. Uses a generous multiplier because the SPA may legitimately
  # call this several times during a single page load (load + save + theme).
  if ($path -eq '/api/consent') {
    $rate = Test-RateLimit -Context $ctx -Multiplier 4
    if (-not $rate.allowed) {
      try {
        if ($ctx.Response -is [System.Net.HttpListenerResponse] -and $rate.retryAfterSec) {
          $ctx.Response.Headers['Retry-After'] = [string]$rate.retryAfterSec
        }
      } catch { }
      Write-Json -Context $ctx -Object @{ error = 'Rate limit exceeded.'; retryAfterSeconds = $rate.retryAfterSec } -StatusCode 429
      return
    }
    if ($false -eq $analyticsConsentState) {
      Clear-AnonymousSessionCookie -Context $ctx
    }
    Write-Json -Context $ctx -Object @{
      ok = $true
      analyticsConsent = $(if ($null -eq $analyticsConsentState) { $null } else { [bool]$analyticsConsentState })
    }
    return
  }

  # 2) Serve individual API endpoints (/api/*)
  if ($path -in @("/api/base","/api/mx","/api/records","/api/whois","/api/dmarc","/api/dkim","/api/cname","/api/reputation")) {
    if (-not (Test-ApiKey -Context $ctx)) {
      Write-Json -Context $ctx -Object @{ error = 'Missing or invalid API key.' } -StatusCode 401
      return
    }

    $rate = Test-RateLimit -Context $ctx
    if (-not $rate.allowed) {
      try {
        if ($ctx.Response -is [System.Net.HttpListenerResponse] -and $rate.retryAfterSec) {
          $ctx.Response.Headers['Retry-After'] = [string]$rate.retryAfterSec
        }
      } catch { }
      Write-Json -Context $ctx -Object @{ error = 'Rate limit exceeded.'; retryAfterSeconds = $rate.retryAfterSec } -StatusCode 429
      return
    }

    $domainRaw = $null
    try { if ($ctx -and $ctx.Request -and $ctx.Request.QueryString) { $domainRaw = $ctx.Request.QueryString["domain"] } } catch { $domainRaw = $null }
    $domain    = ConvertTo-NormalizedDomain $domainRaw

    Write-RequestLog -Context $ctx -Action "API $path" -Domain $domain

    if ([string]::IsNullOrWhiteSpace($domain)) {
      Write-Json -Context $ctx -Object @{ error = "Missing domain parameter." } -StatusCode 400
      return
    }
    if (-not (Test-DomainName -Domain $domain)) {
      Write-Json -Context $ctx -Object @{ error = "Invalid domain parameter." } -StatusCode 400
      return
    }

    # Serialize duplicate work for this domain + endpoint, but allow other endpoints
    # for the same domain to execute in parallel.
    $sem = Get-DomainSemaphore -domain $domain -scope $path
    $null = $sem.Wait()
    try {
      switch ($path) {
        "/api/base"  {
          if ($metricsEnabled -and ($true -eq $analyticsConsentState)) {
            $null = Get-OrCreate-AnonymousSessionId -Context $ctx
            Update-AnonymousMetrics -Domain $domain -Started
          }
          Write-Json -Context $ctx -Object (Get-DnsBaseStatus  -Domain $domain)
          if ($metricsEnabled -and ($true -eq $analyticsConsentState)) { Update-AnonymousMetrics -Domain $domain -Completed }
        }
        "/api/mx"    { Write-Json -Context $ctx -Object (Get-DnsMxStatus    -Domain $domain) }
        "/api/records" { Write-Json -Context $ctx -Object (Get-DnsRecordsStatus -Domain $domain) }
        "/api/whois" { Write-Json -Context $ctx -Object (Get-DomainRegistrationStatus -Domain $domain) }
        "/api/dmarc" { Write-Json -Context $ctx -Object (Get-DnsDmarcStatus -Domain $domain) }
        "/api/dkim"  { Write-Json -Context $ctx -Object (Get-DnsDkimStatus  -Domain $domain) }
        "/api/cname" { Write-Json -Context $ctx -Object (Get-DnsCnameStatus -Domain $domain) }
        "/api/reputation" { Write-Json -Context $ctx -Object (Get-DnsReputationStatus -Domain $domain) }
        default       { Write-Json -Context $ctx -Object @{ error = "Unknown endpoint." } -StatusCode 404 }
      }
    }
    finally {
      try { $null = $sem.Release() } catch {}
    }
    return
  }

  # 2b) Microsoft Entra ID auth: handled entirely client-side in the SPA.
  # The browser uses MSAL to acquire a Microsoft Graph token and calls
  # Graph /me directly (see verifyMsAccount in 20e-HtmlAzureIntegration.ps1).
  # The previous /api/auth/verify route forwarded user bearer tokens to
  # Microsoft Graph from the server, which expanded the trust boundary
  # without adding security. It was removed so the server never handles
  # raw Entra access tokens.
  #
  # The /api/auth/event route below is the consent-gated, header-only
  # successor: after the SPA finishes its own Graph verification it POSTs
  # a single notification with two non-PII headers so we can keep counting
  # anonymous sign-in volume and unique Microsoft-employee bucket counts:
  #
  #   X-ACS-Auth-Account-Key  - SHA-256 hex of (tenantId + ':' + oid),
  #                             computed in the browser via SubtleCrypto.
  #                             Optional; only sent when both claims are
  #                             present. Server HMAC-rehashes it with the
  #                             per-install MetricsHashKey before storing.
  #   X-ACS-Auth-Is-Microsoft - '1' if the SPA classified the user as a
  #                             Microsoft employee (UPN matches
  #                             microsoft.com/microsoftsupport.com),
  #                             otherwise '0'. Worst case a tampered
  #                             value off-by-ones a usage counter, which
  #                             is acceptable for an opt-in analytics
  #                             signal.
  #
  # The route requires analytics consent and applies the standard rate
  # limiter so a noisy client cannot pin a worker.
  if ($path -eq '/api/auth/event') {
    if (-not $metricsEnabled) {
      Write-Json -Context $ctx -Object @{ ok = $true; recorded = $false; reason = 'metrics-disabled' }
      return
    }
    if ($true -ne $analyticsConsentState) {
      # Honor the user's consent choice: do nothing, but acknowledge with 200
      # so the SPA does not retry. Mirrors the /api/consent shape.
      Write-Json -Context $ctx -Object @{ ok = $true; recorded = $false; reason = 'analytics-consent-required' }
      return
    }

    $rate = Test-RateLimit -Context $ctx -Multiplier 4
    if (-not $rate.allowed) {
      try {
        if ($ctx.Response -is [System.Net.HttpListenerResponse] -and $rate.retryAfterSec) {
          $ctx.Response.Headers['Retry-After'] = [string]$rate.retryAfterSec
        }
      } catch { }
      Write-Json -Context $ctx -Object @{ error = 'Rate limit exceeded.'; retryAfterSeconds = $rate.retryAfterSec } -StatusCode 429
      return
    }

    # Read the two opt-in headers via Get-RequestHeaderValue, which already
    # handles both the WebHeaderCollection (HttpListener) and hashtable
    # (TcpListener shim) header shapes.
    $accountKey = Get-RequestHeaderValue -Context $ctx -Name 'X-ACS-Auth-Account-Key'
    $isMsRaw    = Get-RequestHeaderValue -Context $ctx -Name 'X-ACS-Auth-Is-Microsoft'

    # Defensive validation: the account key must look like a SHA-256 hex
    # digest (64 chars, [0-9a-f]). Anything else gets ignored so we never
    # store junk in the unique-employee hash set.
    $accountKeyValid = $false
    if (-not [string]::IsNullOrWhiteSpace($accountKey)) {
      $accountKeyTrimmed = $accountKey.Trim().ToLowerInvariant()
      if ($accountKeyTrimmed -match '^[0-9a-f]{64}$') {
        $accountKey = $accountKeyTrimmed
        $accountKeyValid = $true
      } else {
        $accountKey = $null
      }
    } else {
      $accountKey = $null
    }

    $isMsEmployee = $false
    if (-not [string]::IsNullOrWhiteSpace($isMsRaw)) {
      $isMsTrim = $isMsRaw.Trim().ToLowerInvariant()
      if ($isMsTrim -in @('1', 'true', 'yes', 'on')) { $isMsEmployee = $true }
    }

    try {
      Update-AnonymousAuthMetrics -AccountKey $accountKey -IsMicrosoftEmployee $isMsEmployee
    } catch { $null = $_ }

    Write-Json -Context $ctx -Object @{
      ok = $true
      recorded = $true
      accountKeyAccepted = $accountKeyValid
      isMicrosoftEmployee = $isMsEmployee
    }
    return
  }

  # 3) Serve the aggregated endpoint used by the UI (/dns)
  if ($path -eq "/dns") {
    if (-not (Test-ApiKey -Context $ctx)) {
      Write-Json -Context $ctx -Object @{ error = 'Missing or invalid API key.'; acsReady = $false } -StatusCode 401
      return
    }

    $rate = Test-RateLimit -Context $ctx
    if (-not $rate.allowed) {
      try {
        if ($ctx.Response -is [System.Net.HttpListenerResponse] -and $rate.retryAfterSec) {
          $ctx.Response.Headers['Retry-After'] = [string]$rate.retryAfterSec
        }
      } catch { }
      Write-Json -Context $ctx -Object @{ error = 'Rate limit exceeded.'; retryAfterSeconds = $rate.retryAfterSec; acsReady = $false } -StatusCode 429
      return
    }

    $domainRaw = $null
    try { if ($ctx -and $ctx.Request -and $ctx.Request.QueryString) { $domainRaw = $ctx.Request.QueryString["domain"] } } catch { $domainRaw = $null }
    $domain    = ConvertTo-NormalizedDomain $domainRaw

    Write-RequestLog -Context $ctx -Action "DNS Lookup" -Domain $domain

    if ([string]::IsNullOrWhiteSpace($domain)) {
      Write-Json -Context $ctx -Object @{ error = "Missing domain parameter."; acsReady = $false } -StatusCode 400
      return
    }
    if (-not (Test-DomainName -Domain $domain)) {
      Write-Json -Context $ctx -Object @{ error = "Invalid domain parameter."; acsReady = $false } -StatusCode 400
      return
    }

    # Serialize duplicate work for this domain + endpoint, but allow other endpoints
    # for the same domain to execute in parallel.
    $sem = Get-DomainSemaphore -domain $domain -scope $path
    $null = $sem.Wait()
    try {
      if ($metricsEnabled) { Update-AnonymousMetrics -Domain $domain -Started }
      $result = Get-AcsDnsStatus -Domain $domain
      Write-Json -Context $ctx -Object $result
      if ($metricsEnabled) { Update-AnonymousMetrics -Domain $domain -Completed }
    }
    finally {
      try { $null = $sem.Release() } catch {}
    }
    return
  }

  if ($ctx -and $ctx.Response) {
    $ctx.Response.StatusCode = 404
    $ctx.Response.StatusDescription = "Not Found"
    $ctx.Response.Close()
  }
}
catch {
  # SECURITY: Do NOT echo $_.Exception.Message back to the client. PowerShell
  # exception messages frequently include file paths, stack hints, env var
  # values, or third-party library internals (e.g. "The remote name could
  # not be resolved: 'rdap.nic.example' (proxy=10.1.2.3)"). Returning a
  # generic error keeps the failure observable for the SPA without leaking
  # those details to anonymous callers.
  #
  # The original message is still emitted to the server console via
  # Write-Information so operators can correlate the request log line with
  # the underlying exception when triaging.
  try {
    $errMsg = $null
    try { $errMsg = [string]$_.Exception.Message } catch { $errMsg = '<unavailable>' }
    Write-Information -InformationAction Continue -MessageData "[$((Get-Date).ToString('yyyy-MM-dd HH:mm:ss'))] handler error for path '$path': $errMsg"
  } catch { }
  try { Write-Json -Context $ctx -Object @{ error = 'Internal server error.' } -StatusCode 500 } catch {}
  try { if ($ctx -and $ctx.Response) { $ctx.Response.Close() } } catch {}
}
'@
# ===== HTTP Accept Loop & TcpListener Shim =====

try {
  function ConvertFrom-QueryString {
    param([string]$Query)
    # Minimal query-string parser used by the TcpListener fallback.
    $nvc = [System.Collections.Specialized.NameValueCollection]::new()
    if ([string]::IsNullOrWhiteSpace($Query)) { return $nvc }
    $q = $Query.TrimStart('?')
    if ([string]::IsNullOrWhiteSpace($q)) { return $nvc }
    foreach ($pair in ($q -split '&')) {
      if ([string]::IsNullOrWhiteSpace($pair)) { continue }
      $kv = $pair -split '=', 2
      $k = ($kv[0] -replace '\+',' ')
      $k = [uri]::UnescapeDataString($k)
      $v = ''
      if ($kv.Count -gt 1) {
        $v = ($kv[1] -replace '\+',' ')
        $v = [uri]::UnescapeDataString($v)
      }
      $nvc.Add($k, $v)
    }
    return $nvc
  }

  # ------------------- TcpListener HTTP Shim -------------------
  # When HttpListener is unavailable, these helper functions provide a minimal HTTP/1.1
  # implementation over raw TCP sockets. They parse request lines + headers and build
  # response objects that mimic the HttpListenerResponse API surface.
  function New-TcpContext {
    param(
      [Parameter(Mandatory = $true)]
      [System.Net.Sockets.TcpClient]$Client,
      [Parameter(Mandatory = $true)]
      [string]$RawTarget,
      [Parameter(Mandatory = $true)]
      [hashtable]$Headers
    )

    $remote = $Client.Client.RemoteEndPoint
    $ua = if ($Headers.ContainsKey('user-agent')) { [string]$Headers['user-agent'] } else { $null }

    $pathOnly = $RawTarget
    $query = ''
    $qm = $RawTarget.IndexOf('?')
    if ($qm -ge 0) {
      $pathOnly = $RawTarget.Substring(0, $qm)
      $query = $RawTarget.Substring($qm)
    }

    $url = [uri]::new("http://localhost:$Port$pathOnly$query")
    $qs = ConvertFrom-QueryString -Query $query

    $networkStream = $Client.GetStream()

    # TcpListener fallback response object.
    # It exposes a subset of `HttpListenerResponse`-like properties and a `SendBody()` method.
    # `_extraHeaders` is populated by Set-SecurityHeaders / Set-NoCacheHeaders so
    # the fallback path emits the same CSP, X-Frame-Options, X-Content-Type-Options,
    # Referrer-Policy, CORS, and cache-control headers as the HttpListener path.
    # Without this slot the fallback server mode would silently strip every
    # browser-side defense.
    $resp = [pscustomobject]@{
      StatusCode = 200
      StatusDescription = 'OK'
      ContentType = 'text/plain; charset=utf-8'
      ContentLength64 = [int64]0
      _client = $Client
      _stream = $networkStream
      _sent = $false
      _extraHeaders = [ordered]@{}
    }

    $resp | Add-Member -MemberType ScriptMethod -Name SendBody -Value {
      param([byte[]]$Bytes)
      if ($this._sent) {
        try { $this._client.Close() } catch { }
        return
      }

      $statusText = if ([string]::IsNullOrWhiteSpace($this.StatusDescription)) { 'OK' } else { $this.StatusDescription }
      # SECURITY/CORRECTNESS: HTTP/1.1 requires CRLF (0x0D 0x0A) between headers
      # and after the final blank line. The previous implementation used the
      # double-quoted PowerShell literal "\r\n" which is the four characters
      # `\`, `r`, `\`, `n` and produces a single-line malformed response that
      # browsers reject. Build the header block with explicit `r`n sequences.
      $crlf = "`r`n"
      $headerBuilder = New-Object System.Text.StringBuilder
      [void]$headerBuilder.Append("HTTP/1.1 $($this.StatusCode) $statusText$crlf")
      [void]$headerBuilder.Append("Content-Type: $($this.ContentType)$crlf")
      [void]$headerBuilder.Append("Content-Length: $($Bytes.Length)$crlf")
      [void]$headerBuilder.Append("Connection: close$crlf")
      # Emit any security / cache-control headers the request handler attached
      # via Set-SecurityHeaders / Set-NoCacheHeaders. We strip CR/LF from values
      # defensively so a buggy caller cannot inject extra headers (HTTP response
      # splitting). Skip duplicates of the headers we already wrote above.
      $reserved = @('content-type','content-length','connection')
      if ($null -ne $this._extraHeaders) {
        foreach ($k in @($this._extraHeaders.Keys)) {
          $kn = ([string]$k).Trim()
          if ([string]::IsNullOrWhiteSpace($kn)) { continue }
          if ($reserved -contains $kn.ToLowerInvariant()) { continue }
          $v = [string]$this._extraHeaders[$k]
          if ($null -eq $v) { continue }
          $v = $v -replace "[`r`n]", ' '
          [void]$headerBuilder.Append("$kn`: $v$crlf")
        }
      }
      [void]$headerBuilder.Append($crlf)
      $headerBytes = [Text.Encoding]::ASCII.GetBytes($headerBuilder.ToString())

      try {
        $this._stream.Write($headerBytes, 0, $headerBytes.Length)
        if ($Bytes.Length -gt 0) {
          $this._stream.Write($Bytes, 0, $Bytes.Length)
        }
        $this._stream.Flush()
      } finally {
        $this._sent = $true
        try { $this._stream.Dispose() } catch { }
        try { $this._client.Close() } catch { }
      }
    } | Out-Null

    $resp | Add-Member -MemberType ScriptMethod -Name Close -Value {
      if ($this._sent) {
        try { $this._client.Close() } catch { }
        return
      }
      $this.SendBody([byte[]]@())
    } | Out-Null

    $req = [pscustomobject]@{
      Url = $url
      QueryString = $qs
      UserAgent = $ua
      RemoteEndPoint = $remote
    }

    return [pscustomobject]@{ Request = $req; Response = $resp }
  }

  # Read and parse an HTTP/1.1 request from a raw TCP stream (request line + headers).
  # Only GET and POST are supported by the TcpListener server mode.
  function Read-TcpHttpRequest {
    param(
      [Parameter(Mandatory = $true)]
      [System.Net.Sockets.TcpClient]$Client
    )

    # Extremely small HTTP/1.1 request reader (GET/POST).
    # We only need the request line + headers to route requests and read query strings.
    # SECURITY: cap the request line length, individual header line length, and
    # the total number of headers so a peer that opens a TCP connection and
    # streams an unbounded line cannot tie up a worker indefinitely or exhaust
    # memory. These limits are deliberately generous compared to real browsers
    # (which send sub-kilobyte request lines) but small enough to fail fast on
    # abuse.
    $maxRequestLineBytes = 8192   # 8 KB request line cap
    $maxHeaderLineBytes  = 8192   # 8 KB per header line
    $maxHeaderCount      = 100    # max distinct headers
    # Cap the POST request body we are willing to read/discard. /api/consent is
    # the only POST endpoint today and its payload is a tiny JSON document; a
    # generous cap is plenty and prevents an attacker from streaming unbounded
    # bytes into the worker. Honor the operator's configured cap from
    # ACS_MAX_REQUEST_BODY_BYTES (set in 00-Header.ps1) and clamp to a hard
    # ceiling so the fallback never allocates an unreasonable buffer even if
    # the env var is mis-configured.
    $maxRequestBodyBytes = 65536  # 64 KB request body cap (default)
    try {
      if ($env:ACS_MAX_REQUEST_BODY_BYTES -and $env:ACS_MAX_REQUEST_BODY_BYTES -match '^\d+$') {
        $envCap = [int]$env:ACS_MAX_REQUEST_BODY_BYTES
        if ($envCap -gt 0) {
          # Hard ceiling of 1 MB so the fallback can never allocate gigabyte buffers.
          $maxRequestBodyBytes = [Math]::Min($envCap, 1048576)
        }
      }
    } catch { }

    # SECURITY: Bound how long we are willing to wait for the peer to send
    # bytes. Without these, a slow-loris client could dribble data within
    # the per-line caps and tie up a worker indefinitely. 15 seconds is
    # comfortably above any normal browser/curl latency.
    try { $Client.ReceiveTimeout = 15000 } catch { }
    try { $Client.SendTimeout    = 15000 } catch { }

    $stream = $Client.GetStream()
    try { $stream.ReadTimeout  = 15000 } catch { }
    try { $stream.WriteTimeout = 15000 } catch { }
    # SECURITY/CORRECTNESS: use UTF-8 for the full reader. UTF-8 is ASCII-
    # compatible so the request line + header parsing (which only deals with
    # ASCII per HTTP/1.1) is unaffected, but POST bodies (e.g. JSON for
    # /api/consent if it ever consumes a request body in this fallback path)
    # are decoded correctly instead of being silently mangled by an ASCII
    # decoder when they contain bytes >= 0x80.
    $reader = [System.IO.StreamReader]::new($stream, [Text.Encoding]::UTF8, $false, 8192, $true)

    try {
      $line1 = $reader.ReadLine()
    } catch {
      # Read timeout / IO error; treat as a malformed request so the caller closes the socket.
      return $null
    }
    if ([string]::IsNullOrWhiteSpace($line1)) { return $null }
    if ($line1.Length -gt $maxRequestLineBytes) { return $null }

    $parts = $line1 -split '\s+'
    if ($parts.Count -lt 2) { return $null }

    $method = $parts[0].Trim().ToUpperInvariant()
    $target = $parts[1].Trim()

    $headers = @{}
    $headerCount = 0
    while ($true) {
      try {
        $line = $reader.ReadLine()
      } catch {
        # Read timeout / IO error mid-headers; treat as malformed.
        return $null
      }
      if ($null -eq $line) { break }
      if ($line -eq '') { break }
      if ($line.Length -gt $maxHeaderLineBytes) { return $null }
      $headerCount++
      if ($headerCount -gt $maxHeaderCount) { return $null }
      $idx = $line.IndexOf(':')
      if ($idx -le 0) { continue }
      $hName = $line.Substring(0, $idx).Trim().ToLowerInvariant()
      $hValue = $line.Substring($idx + 1).Trim()
      $headers[$hName] = $hValue
    }

    # Drain the POST body (if any) so the StreamReader buffer and the
    # underlying network stream are consumed before we hand control to the
    # request handler. Today no handler reads the body (the consent route is
    # driven entirely by the X-ACS-Cookie-Consent header), so we simply
    # discard up to $maxRequestBodyBytes. If a handler ever needs the body in
    # this fallback mode, the captured value is exposed on the returned
    # object as `Body`.
    $body = $null
    if ($method -eq 'POST') {
      $contentLength = 0
      if ($headers.ContainsKey('content-length')) {
        $clRaw = [string]$headers['content-length']
        [void][int]::TryParse($clRaw, [ref]$contentLength)
      }
      if ($contentLength -gt 0) {
        $toRead = [Math]::Min($contentLength, $maxRequestBodyBytes)
        try {
          $buffer = New-Object char[] $toRead
          $totalRead = 0
          while ($totalRead -lt $toRead) {
            $chunk = $reader.Read($buffer, $totalRead, ($toRead - $totalRead))
            if ($chunk -le 0) { break }
            $totalRead += $chunk
          }
          if ($totalRead -gt 0) {
            $body = New-Object string ($buffer, 0, $totalRead)
          }
        } catch { $body = $null }
      }
    }

    return [pscustomobject]@{ Method = $method; Target = $target; Headers = $headers; Body = $body }
  }

  if ($serverMode -eq 'HttpListener') {
    # Primary server mode: HttpListener (best supported on Windows).
    while ($listener.IsListening) {
      try {
        $ctx = $listener.GetContext()

        # Handle CORS preflight (OPTIONS) requests inline to avoid RunspacePool overhead.
        try {
          if ($ctx.Request.HttpMethod -eq 'OPTIONS') {
            Set-SecurityHeaders -Context $ctx
            $ctx.Response.StatusCode = 204
            $ctx.Response.ContentLength64 = 0
            $ctx.Response.Close()
            continue
          }
        } catch { }

        # Fast-path metrics to avoid runspace contention during lookups.
        try { $absPath = $ctx.Request.Url.AbsolutePath } catch { $absPath = $null }
        if ($absPath -and ($absPath.TrimEnd('/') -ieq '/api/metrics')) {
          # SECURITY: even though /api/metrics is cheap, it can take the metrics
          # file mutex and read+JSON-parse the persistence file, which is a
          # cheap-but-real DoS amplifier under sustained polling. Apply a
          # generous rate limit (10x the per-endpoint limit) so the SPA's
          # auto-refresh keeps working but a tight loop gets throttled.
          $metricsRate = Test-RateLimit -Context $ctx -Multiplier 10
          if (-not $metricsRate.allowed) {
            try {
              if ($ctx.Response -is [System.Net.HttpListenerResponse] -and $metricsRate.retryAfterSec) {
                $ctx.Response.Headers['Retry-After'] = [string]$metricsRate.retryAfterSec
              }
            } catch { }
            Write-Json -Context $ctx -Object @{ error = 'Rate limit exceeded.'; retryAfterSeconds = $metricsRate.retryAfterSec } -StatusCode 429
            continue
          }
          # Respond inline (fast and avoids ThreadPool runspace issues).
          Handle-MetricsRequest -Context $ctx -MetricsEnabled $anonMetricsEnabled
          continue
        }

        # Run the handler in the RunspacePool so multiple requests can be processed concurrently.
        $ps = [PowerShell]::Create()
        $ps.RunspacePool = $pool
        $null = $ps.AddScript($handlerScript).AddArgument($ctx).AddArgument($htmlPage).AddArgument($domainLocks).AddArgument($msalLocalPath).AddArgument($script:TosPageHtml).AddArgument($script:PrivacyPageHtml).AddArgument($script:AssetsRoot)

        $async = $ps.BeginInvoke()
        $null = Register-InflightInvocation -PowerShellInstance $ps -AsyncResult $async

        Invoke-InflightCleanup
      }
      catch [System.Net.HttpListenerException] {
        Write-Error -Message "HttpListenerException: $($_.Exception.Message)" -ErrorAction Continue
        break
      }
      catch {
        Write-Error -Message "HttpListener loop error: $($_.Exception.Message)" -ErrorAction Continue
        break
      }
    }
  }
  elseif ($serverMode -eq 'TcpListener' -and $tcpListener) {
    # Fallback server mode: TcpListener (for platforms where HttpListener is unavailable).
    # Only GET is supported here; it's enough for the SPA + JSON endpoints.
    while ($true) {
      $client = $tcpListener.AcceptTcpClient()
      if ($null -eq $client) { continue }

      $req = $null
      try {
        $req = Read-TcpHttpRequest -Client $client
        if ($null -eq $req) {
          try { $client.Close() } catch { }
          continue
        }

        if ($req.Method -ne 'GET' -and $req.Method -ne 'POST') {
          $ctx = New-TcpContext -Client $client -RawTarget ($req.Target) -Headers $req.Headers
          $ctx.Response.StatusCode = 405
          $ctx.Response.StatusDescription = 'Method Not Allowed'
          $ctx.Response.ContentType = 'text/plain; charset=utf-8'
          $ctx.Response.SendBody([Text.Encoding]::UTF8.GetBytes('Method Not Allowed'))
          continue
        }

        $ctx = New-TcpContext -Client $client -RawTarget ($req.Target) -Headers $req.Headers

        # Fast-path metrics for TcpListener fallback as well.
        try { $absPath = $ctx.Request.Url.AbsolutePath } catch { $absPath = $null }
        if ($absPath -and ($absPath.TrimEnd('/') -ieq '/api/metrics')) {
          # See HttpListener fast-path above for the rationale on rate-limiting
          # the metrics endpoint with a 10x multiplier.
          $metricsRate = Test-RateLimit -Context $ctx -Multiplier 10
          if (-not $metricsRate.allowed) {
            Write-Json -Context $ctx -Object @{ error = 'Rate limit exceeded.'; retryAfterSeconds = $metricsRate.retryAfterSec } -StatusCode 429
            continue
          }
          Handle-MetricsRequest -Context $ctx -MetricsEnabled $anonMetricsEnabled
          continue
        }

        # Run the same handler script used by HttpListener.
        $ps = [PowerShell]::Create()
        $ps.RunspacePool = $pool
        $null = $ps.AddScript($handlerScript).AddArgument($ctx).AddArgument($htmlPage).AddArgument($domainLocks).AddArgument($msalLocalPath).AddArgument($script:TosPageHtml).AddArgument($script:PrivacyPageHtml).AddArgument($script:AssetsRoot)

        $async = $ps.BeginInvoke()
        $null = Register-InflightInvocation -PowerShellInstance $ps -AsyncResult $async

        Invoke-InflightCleanup
      }
      catch [System.Net.Sockets.SocketException] {
        Write-Error -Message "TcpListener SocketException: $($_.Exception.Message)" -ErrorAction Continue
        try { $client.Close() } catch { }
      }
      catch {
        Write-Error -Message "TcpListener loop error: $($_.Exception.Message)" -ErrorAction Continue
        try { $client.Close() } catch { }
      }
    }
  }
  else {
    Write-Error -Message "Server did not start. HttpListener unavailable and TcpListener could not be initialized." -ErrorAction Continue
  }
}
catch {
  Write-Error -ErrorRecord $_
}
# ===== Graceful Shutdown =====
finally {
# ------------------- GRACEFUL SHUTDOWN -------------------
# Stop listeners, persist final metrics, drain in-flight requests, and dispose the pool.
try { if ($listener -and $listener.IsListening) { $listener.Stop() } } catch { $null = $_ }
try { if ($tcpListener) { $tcpListener.Stop() } } catch { $null = $_ }

  # Persist metrics one last time.
  try { Save-AnonymousMetricsPersisted -Force } catch { $null = $_ }

  Invoke-InflightCleanup
  foreach ($invocationId in @($inflight.Keys)) {
    Complete-InflightInvocation -InvocationId $invocationId -Force
  }
  try { $pool.Close(); $pool.Dispose() } catch { $null = $_ }
  Write-Information -InformationAction Continue -MessageData "Server stopped."
}
